var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 아무나 저 여자 좀 막아 봐!","JPN":"くそっ！　誰かあの女を止めろ！","ENG":"Darn it! Somebody stop her!","TWN":"可惡！給我攔住那個女人！"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"닥치고 도망치기나 해! 형님도 한 방에 처박히는 거 못 봤어?!","JPN":"黙って逃げろ！　兄貴だって一発で吹っ飛ばされたんだぞ！","ENG":"Just shut up and run! Didn't you see that thing take him out in a single blow?","TWN":"閉嘴，快點逃吧！沒看到老大根本就無法招架嗎？！"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"어디로 도망치란 거야! 벽이고 바닥이고 움직이기만 하면 칼이 튀어나오는데!","JPN":"どこに逃げればいいんだよ！　壁も床も、動くだけで剣が飛び出してくるのに！","ENG":"Run? Where to?! We got blades popping out of walls and the floor the moment we move!","TWN":"往哪逃啊！只要一動，牆和地面都會冒出刀刃！"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"이거 다들 군기가 빠졌군.","JPN":"やれやれ、使えない奴ばっかりだな。","ENG":"Looks like we've got a discipline issue among the ranks.","TWN":"簡直就是一盤散沙，還像話嗎。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"내 허락도 없이 도망을 치다니, 요즘 살 만한가 보지?","JPN":"俺の許可なしで逃げるとは、いい度胸だな？","ENG":"I must have grown soft on you, letting you think you can flee without my permission.","TWN":"沒我的允許竟然敢逃走，最近是活的太爽了吧？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"크, 큰 형님! 오셨습니까!","JPN":"ボ、ボス！","ENG":"B-boss! You're here!","TWN":"大、大哥！您來了！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"저 여자 때문입니다! 저 여자가 우리 조직을 우습게 보고......!","JPN":"あの女のせいです！　あいつが俺らをバカにしやがって……","ENG":"It's all because of that broad! She thinks she can mess with our gang—","TWN":"都是那個女人！那個女人戲弄我們組織……！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"컥...... 커헉......","JPN":"ぐあ……ガハッ……","ENG":"Ack... Aack...","TWN":"咳……呃……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"호들갑 좀 떨지 마라. 나도 모르게 주먹이 나갔잖아.","JPN":"大げさだぞ。でかい声出すもんだからつい手が出てしまったじゃないか。","ENG":"Don't get so riled up. You got my fists going before I could think.","TWN":"別在那大驚小怪的，搞的我身體都不自覺的出拳了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"안 그러신가, 아르세니코 패밀리의 후계자 아가씨.","JPN":"この事態をどう思うのかね？　アルセニコファミリーの後継者のお嬢ちゃん。","ENG":"Ain't that right, the heiress of the Arsenicos?","TWN":"是不是啊，阿塞妮克家族的繼承人小姐。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어째 재수없는 이름이다 싶더니 네놈 사업장이었군.","JPN":"ださい組織名だと思ったら、お前の事業所だったのか。","ENG":"No wonder the name was so lame. So this was your business.","TWN":"我想說這裡名字怎麼如此糟糕，原來是你的窩啊。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"부하들을 위해 덤비겠다면 말리지 않겠어.","JPN":"部下の前でメンツを立てるためにかかってくるなら、応じてやるよ。","ENG":"I won't stop you if you're going to fight for your men.","TWN":"如果你要為你的部下報仇，我沒意見。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하핫. 다른 얼뜨기라면 그랬겠지.","JPN":"ハハッ。他のならず者ならそうするだろうが、俺は違うぞ。","ENG":"Hah hah. I would have, if it was anyone else.","TWN":"哈哈。如果是別人的確可能馬上就衝上去吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하지만 옛 동업자 상대로 굳이 리스크를 감수하고 싶진 않아.","JPN":"かつての同業者を相手に、わざわざリスクを冒す必要はないだろう。","ENG":"But I don't want to take unnecessary risks against a former partner.","TWN":"但對於以前是合夥人的你，我不想承擔風險。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"누가 동업자라는 거냐. 난 이제 패밀리와 아무 관계없어.","JPN":"同業者だと？　私はもうファミリーとは関係ないんだが。","ENG":"Who are you calling a partner? I've got nothing to do with the Family anymore.","TWN":"誰是你合夥人。我現在跟家族已經沒有關係了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 말은 아버지한테나 가서 하시지.","JPN":"そんなことは親父にでも言え。","ENG":"Why don't you try saying that to my father?","TWN":"這句話你還是留著跟父親說吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};